qry:select.qry:xquery:
					for $r in SQL('
{%? (#SOURCE:@START='') {% %} {% fromrow {%=#SOURCE:@START %} %} %} 
 {%? (#SOURCE:@LEN='') {% %} {% maxsize {%=#SOURCE:@LEN %} %} %} 
select
  PER02_PERSONAL_EMP.oi_personal_emp as ID,
  PER02_PERSONAL_EMP.e_numero_legajo as COD,
  PER01_PERSONAL.d_ape_y_nom as DES,
  PER02_PERSONAL_EMP.oi_empresa as PARENT
from
  PER02_PERSONAL_EMP,
  PER01_PERSONAL
join
  PER02_PERSONAL_EMP.OI_PERSONAL inner PER01_PERSONAL.OI_PERSONAL 
Where
  1=1 
{%? (#SOURCE:@OI_FIND='') {% %} {% and ID={#SOURCE:@OI_FIND} %} %} 
{%? (#SOURCE:@TXT_FIND='') {% %} {% and (contain(DES,{#SOURCE:@TXT_FIND}) or contain(COD,{#SOURCE:@TXT_FIND})) %} %} 
{%? (#SOURCE:@OI_PARENT='') {% %} {% and PARENT={#SOURCE:@OI_PARENT} %} %} 

{%? (#SOURCE:@WHERE='') {% %} {% and {%=#SOURCE:@WHERE %} %} %}
{%? (#SOURCE:@ORDERBY='') {% order by DES asc %} {%  order by {%=#SOURCE:@ORDERBY %} asc %} %}')/ROWS/ROW

			for $r in sql(' 
	SELECT ORG02_ESTRUC_PERS.oi_estruc_pers, ORG02_ESTRUC_PERS.oi_estructura
	FROM ORG02_ESTRUC_PERS
	WHERE ORG02_ESTRUC_PERS.oi_clase_org = {#SOURCE:@oi_clase_org}
	AND ORG02_ESTRUC_PERS.oi_personal_emp = {#SOURCE:@oi_personal_emp}
')/ROWS/ROW

for $r in sql('		
SELECT ORG02_ESTRUCTURAS.oi_estructura, d_valor = {%=#SOURCE:@d_valor%}
FROM ORG02_ESTRUCTURAS
WHERE ORG02_ESTRUCTURAS.oi_estr_padre = {#SOURCE:@oi_estructura}						 
')/ROWS/ROW

					for $r in sql('  
SELECT 
L.oi_personal_emp, 
L.e_numero_legajo {%? (#F:@orden!=''){% ,
{%=#F:@orden %} as Orden %}{% %} %}
FROM 
PER02_PERSONAL_EMP AS L,PER01_PERSONAL AS PER
{%? (#F:@oi_clase_org !='') {% , ORG02_ESTRUC_PERS%} {% %} %}
JOIN 
L.oi_personal INNER PER.oi_personal
{%? (#F:@oi_clase_org !='') {% ,L.oi_personal_emp INNER ORG02_ESTRUC_PERS.oi_personal_emp%} {% %} %}
WHERE 
L.oi_empresa = {#PARAM:@oi_empresa}					              
{%? (#PARAM:@oi_personal_emp != '') {% AND L.oi_personal_emp = {#PARAM:@oi_personal_emp} %} {% %} %}
{%? (#F:@oi_clase_org !='') {% AND ORG02_ESTRUC_PERS.oi_clase_org = {#F:@oi_clase_org} %} {% %} %}
{%? (#F:@oi_empresa != '') {% AND L.oi_empresa = {#F:@oi_empresa} %} {% %} %}
{%? (#F:@oi_indic_activo != '') {% AND L.oi_indic_activo = {#F:@oi_indic_activo} %} {% %} %}
{%? (#F:@oi_tipo_personal != '') {% AND L.oi_tipo_personal = {#F:@oi_tipo_personal} %} {% %} %}
{%? (#F:@oi_ctro_costo_ult != '') {% AND L.oi_ctro_costo_ult = {#F:@oi_ctro_costo_ult} %} {% %} %}    

ORDER BY 
{%? (#F:@orden!='') {% orden %} {% e_numero_legajo %} %} ASC 
')/ROWS

					for $r in sql('
{%? (#FILTER:@maxsize != "")
{% MAXSIZE {%= #FILTER:@maxsize %}%}
{%%}
%}    
SELECT     
	LIC.oi_licencia as LICENCIA_VAL,
	LIC.d_licencia as LICENCIA_DES,
	LIC_PER.oi_licencia_per as OI_LIC_PER,
	LIC_PER.f_inicio as F_INICIO,
	LIC_PER.f_fin as F_FIN
FROM
	PER16_LICENCIAS as LIC, 
	PER02_LICEN_PER as LIC_PER, 
	PER02_PERSONAL_EMP as LEG  
JOIN
	LIC.oi_licencia INNER LIC_PER.oi_licencia,
	LIC_PER.oi_personal_emp INNER LEG.oi_personal_emp
WHERE    
	LEG.oi_personal_emp = {#FILTER:@oi_personal_emp}    
	AND LIC_PER.f_inicio >= { #PARAM:@fi }
	AND LIC_PER.f_fin <= { #PARAM:@ff }
	{%? (#FILTER:@ids != "")
{% AND LIC.oi_licencia not in ({%= #FILTER:@ids %})%}
{%%}
%}
ORDER BY
	F_INICIO DESC
')ROWS/ROW

for $r in SQL('
SELECT CONV.oi_convenio as CONV_VAL, CONV.d_convenio as CONV_DES FROM PER02_PERSONAL_EMP as PER_EMP, ORG18_CATEGORIAS as CAT, ORG18_CONVENIOS as CONV JOIN PER_EMP.oi_categoria_ult LEFT CAT.oi_categoria, CAT.oi_convenio LEFT CONV.oi_convenio WHERE PER_EMP.oi_personal_emp = {$FILTER/@oi_personal_emp}
')/ROWS/ROW

					for $r in SQL('
