{%? (#SOURCE:@TXT_FIND='') {% %} {% and (contain(PER01_PERSONAL.d_ape_y_nom,{#SOURCE:@TXT_FIND}) or contain(PER02_PERSONAL_EMP.e_numero_legajo,{#SOURCE:@TXT_FIND})) %} %} 
{%? (#SOURCE:@OI_PARENT='') {% %} {% and PER02_PERSONAL_EMP.oi_empresa={#SOURCE:@OI_PARENT} %} %} 

