{%? (#SOURCE:@WHERE = 'C') {%	AND PER02_PERSONAL_EMP.l_confidencial = 1%}{% AND PER02_PERSONAL_EMP.l_confidencial = 0 %} %} 
%} 
{%	%}
%}


GROUP BY SEC.policy')/ROWS/ROW

for $r in SQL('
