')/ROWS/ROW

for $r in SQL(' {%? (#SOURCE:@START='') {% %} {% fromrow {%=#SOURCE:@START %} %} %} {%? (#SOURCE:@LEN='') {% %} {% maxsize {%=#SOURCE:@LEN %} %} %} select PER02_CARGOS.oi_cargo as ID, PER02_CARGOS.e_cargo as COD, ( ORG18_CONVENIOS.c_convenio || \' \' || ORG18_CATEGORIAS.c_categoria || \' \' || IIFISNULL(ORG03_UBICACIONES.c_ubicacion, \'\') || \' \' || IIFISNULL(PER40_GRUPO_COSTO.c_grupo_costo, \'\') || \' \' || IIFISNULL(PER39_MATERIAS.d_materia, \'\') ) as DES, PER02_PERSONAL_EMP.oi_personal_emp as PARENT from PER02_CARGOS, ORG18_CATEGORIAS, PER02_PERSONAL_EMP, ORG18_CONVENIOS, ORG03_UBICACIONES, PER39_MATERIAS, PER40_GRUPO_COSTO join PER02_CARGOS.oi_personal_emp INNER PER02_PERSONAL_EMP.oi_personal_emp, PER02_CARGOS.oi_categoria INNER ORG18_CATEGORIAS.oi_categoria, ORG18_CATEGORIAS.oi_convenio INNER ORG18_CONVENIOS.oi_convenio, PER02_CARGOS.oi_materia LEFT OUTER PER39_MATERIAS.oi_materia, PER02_CARGOS.oi_ubicacion LEFT OUTER ORG03_UBICACIONES.oi_ubicacion, PER02_CARGOS.oi_grupo_costo LEFT OUTER PER40_GRUPO_COSTO.oi_grupo_costo Where 1=1 {%? (#SOURCE:@OI_FIND='') {% %} {% and ID={#SOURCE:@OI_FIND} %} %} {%? (#SOURCE:@TXT_FIND='') {% %} {% and (contain(ORG18_CATEGORIAS.c_categoria, {#SOURCE:@TXT_FIND})) %} %} {%? (#SOURCE:@OI_PARENT='') {% %} {% and PARENT={#SOURCE:@OI_PARENT} %} %}
